/* Expanded ARGB pixels (filled lazily; .bss, so it costs no disk space and
 * untouched pages are never committed). */
static unsigned int g_texpx[ARENA_TOTAL_PX];
static unsigned char g_texdecoded[ARENA_NTEX];
static Image g_teximg[ARENA_NTEX];

static const Image *tex_get(int t)
{
    const TexDef *d;
    unsigned int *dst;
    int i, n;
    if (t < 0 || t >= ARENA_NTEX) return 0;
    if (!g_texdecoded[t]) {
        d   = &g_texdef[t];
        dst = &g_texpx[d->off];
        n   = (int)d->w * (int)d->h;
        for (i = 0; i < n; i++) {
            int p = d->idx[i];
            dst[i] = (p < d->npal) ? d->pal[p] : 0xFF000000u;
        }
        g_teximg[t].w  = d->w;
        g_teximg[t].h  = d->h;
        g_teximg[t].px = dst;
        g_texdecoded[t] = 1;
    }
    return &g_teximg[t];
}

/* slots per theme: 0 wall0, 1 wall1, 2 floor0, 3 floor1, 4 ceil, 5 sky */
/* There are 5 baked texture themes (0..4). Levels beyond that (e.g. the outdoor
 * Dust Storm at index 5) reuse the sandy Colosseum set (3) as their base theme;
 * their surfaces mostly come from the /ARENA MAT_* art textures anyway.        */
#define NUM_TEX_THEMES 5
static int theme_wrap(int theme)
{
    if (theme >= NUM_TEX_THEMES) return 3;       /* desert -> sandy colosseum   */
    theme %= NUM_TEX_THEMES;
    if (theme < 0) theme += NUM_TEX_THEMES;
    return theme;
}

/* Real photo-scan texture override, loaded from /ARENA/TEX (zortch CC0 pack,
 * mutantleg). Each theme has T<t>W0/W1 walls, T<t>F0/F1 floors, T<t>C ceiling
 * as 256x256 24-bit BMPs. pol_load_bmp caches and returns NULL when the file
 * is missing or unreadable, so a stripped image falls straight back to the
 * baked palettized texture below and the arena never loses its surfaces. */
static const Image *tex_disk(char kind, int theme, int id)
{
    int t = theme_wrap(theme);
    if (kind == 'C') {
        char c[] = "/ARENA/TEX/T0C.BMP";
        c[12] = (char)('0' + t);
        return pol_load_bmp(c);
    }
    char p[] = "/ARENA/TEX/T0X0.BMP";
    p[12] = (char)('0' + t);
    p[13] = kind;                       /* 'W' wall, 'F' floor */
    p[14] = (char)('0' + (id & 1));
    return pol_load_bmp(p);
}

const Image *tx_wall(int theme, int id)
{
    if (id < 0) id = -id;
    const Image *d = tex_disk('W', theme, id);
    if (d) return d;
    return tex_get(theme_wrap(theme) * 6 + (id & 1));
}

const Image *tx_floor(int theme, int id)
{
    if (id < 0) id = -id;
    const Image *d = tex_disk('F', theme, id);
    if (d) return d;
    return tex_get(theme_wrap(theme) * 6 + 2 + (id & 1));
}

const Image *tx_ceil(int theme, int id)
{
    (void)id;   /* one ceiling material per theme */
    const Image *d = tex_disk('C', theme, 0);
    if (d) return d;
    return tex_get(theme_wrap(theme) * 6 + 4);
}

const Image *tx_sky(int theme)
{
    return tex_get(theme_wrap(theme) * 6 + 5);
}
